import asyncio
import json
from patchright.async_api import async_playwright

async def inspect_page():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        # Find the Boss直聘 page
        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        if not boss_page:
            print("❌ 没找到 Boss直聘 页面")
            for page in context.pages:
                print(f"  - {page.url}")
            return

        print(f"✅ 当前页面: {boss_page.url}")
        print(f"   标题: {await boss_page.title()}")
        print()

        # Extract DOM structure for search page
        result = await boss_page.evaluate("""
        () => {
            const info = {};

            // 1. 搜索相关元素
            info.search = {};

            // 搜索输入框
            const inputs = document.querySelectorAll('input');
            info.search.inputs = Array.from(inputs).map(el => ({
                tag: 'input',
                type: el.type,
                placeholder: el.placeholder,
                name: el.name,
                id: el.id,
                className: el.className,
                value: el.value
            })).filter(x => x.placeholder || x.name || x.id);

            // 搜索按钮
            const buttons = document.querySelectorAll('button');
            info.search.buttons = Array.from(buttons).map(el => ({
                tag: 'button',
                text: (el.innerText || '').trim().substring(0, 50),
                className: el.className,
                id: el.id,
                type: el.type
            })).filter(x => x.text);

            // 2. 候选人卡片
            info.candidates = {};

            // 查找可能的卡片容器
            const cardPatterns = [
                '[class*="card"]', '[class*="geek"]', '[class*="candidate"]',
                '[class*="recommend"]', '[class*="user-item"]', '[class*="list-item"]',
                'li[class]'
            ];

            for (const pattern of cardPatterns) {
                const els = document.querySelectorAll(pattern);
                if (els.length > 0) {
                    const samples = Array.from(els).slice(0, 3).map(el => ({
                        tag: el.tagName.toLowerCase(),
                        className: el.className,
                        id: el.id,
                        childCount: el.children.length,
                        textPreview: (el.innerText || '').trim().substring(0, 100),
                        hasLink: !!el.querySelector('a[href]'),
                        linkHref: el.querySelector('a[href]')?.href || '',
                        rect: el.getBoundingClientRect()
                    }));
                    if (samples.some(s => s.textPreview.length > 10)) {
                        info.candidates[pattern] = {
                            count: els.length,
                            samples: samples
                        };
                    }
                }
            }

            // 3. 滚动容器
            info.scrollContainers = [];
            const allEls = document.querySelectorAll('*');
            for (const el of allEls) {
                const style = window.getComputedStyle(el);
                const overflowY = style.overflowY;
                if ((overflowY === 'auto' || overflowY === 'scroll') && el.scrollHeight > el.clientHeight + 50) {
                    info.scrollContainers.push({
                        tag: el.tagName.toLowerCase(),
                        className: el.className,
                        id: el.id,
                        scrollHeight: el.scrollHeight,
                        clientHeight: el.clientHeight,
                        overflowY: overflowY,
                        childCount: el.children.length
                    });
                }
            }

            // 4. 页面主要结构
            info.mainStructure = {};
            const main = document.querySelector('main, [class*="main"], [class*="content"], [role="main"]');
            if (main) {
                info.mainStructure.main = {
                    tag: main.tagName.toLowerCase(),
                    className: main.className,
                    id: main.id
                };
            }

            // 5. 链接中包含 geek 的
            const geekLinks = document.querySelectorAll('a[href*="geek"]');
            info.geekLinks = Array.from(geekLinks).slice(0, 5).map(el => ({
                href: el.href,
                text: (el.innerText || '').trim().substring(0, 50),
                className: el.className,
                parentClass: el.parentElement?.className || ''
            }));

            return info;
        }
        """)

        print(json.dumps(result, ensure_ascii=False, indent=2))

asyncio.run(inspect_page())
