import asyncio
import json
from patchright.async_api import async_playwright

async def deep_inspect():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        if not boss_page:
            print("❌ 没找到 Boss直聘 页面")
            return

        print(f"当前页面: {boss_page.url}\n")

        # 深度分析整个页面结构
        result = await boss_page.evaluate("""
        () => {
            const info = {};

            // 1. 顶层结构 (body > 直接子元素)
            info.topLevel = Array.from(document.body.children).map(el => ({
                tag: el.tagName.toLowerCase(),
                className: (el.className || '').toString().substring(0, 100),
                id: el.id,
                visible: el.offsetHeight > 0,
                rect: el.getBoundingClientRect(),
                childCount: el.children.length
            }));

            // 2. 所有包含多个子元素的列表容器 (可能是候选人列表)
            info.listContainers = [];
            document.querySelectorAll('*').forEach(el => {
                if (el.children.length >= 3 && el.children.length <= 100) {
                    const children = Array.from(el.children);
                    const firstChildClass = children[0]?.className || '';
                    // 检查子元素是否有相同的 class（列表特征）
                    const sameClass = children.filter(c => c.className === firstChildClass).length;
                    if (sameClass >= 3 && firstChildClass) {
                        const rect = el.getBoundingClientRect();
                        if (rect.height > 200 && rect.width > 200) {
                            info.listContainers.push({
                                tag: el.tagName.toLowerCase(),
                                className: (el.className || '').toString().substring(0, 120),
                                id: el.id,
                                childCount: el.children.length,
                                childClass: firstChildClass.substring(0, 100),
                                childTag: children[0].tagName.toLowerCase(),
                                sameClassCount: sameClass,
                                rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                                sampleChildText: (children[0].innerText || '').substring(0, 120)
                            });
                        }
                    }
                }
            });

            // 3. resume-detail-wrap 内容详情
            const resumeWrap = document.querySelector('.resume-detail-wrap');
            if (resumeWrap) {
                info.resumeDetail = {
                    className: resumeWrap.className,
                    childStructure: Array.from(resumeWrap.querySelectorAll(':scope > * > *')).slice(0, 10).map(el => ({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 80),
                        textPreview: (el.innerText || '').substring(0, 80)
                    }))
                };
            }

            // 4. 所有 a 链接中包含有意义路径的
            info.meaningfulLinks = [];
            document.querySelectorAll('a[href]').forEach(el => {
                const href = el.href;
                if (href.includes('geek') || href.includes('search') || href.includes('chat') || href.includes('recommend')) {
                    info.meaningfulLinks.push({
                        href: href,
                        text: (el.innerText || '').trim().substring(0, 50),
                        className: (el.className || '').toString().substring(0, 60),
                        parentClass: (el.parentElement?.className || '').toString().substring(0, 60)
                    });
                }
            });

            // 5. 当前页面所有可交互按钮
            info.interactiveButtons = [];
            document.querySelectorAll('button, [role="button"], a.btn, [class*="btn"]').forEach(el => {
                const text = (el.innerText || '').trim();
                if (text && text.length < 50) {
                    const rect = el.getBoundingClientRect();
                    if (rect.height > 0) {
                        info.interactiveButtons.push({
                            tag: el.tagName.toLowerCase(),
                            text: text.substring(0, 40),
                            className: (el.className || '').toString().substring(0, 80),
                            rect: { x: Math.round(rect.x), y: Math.round(rect.y), w: Math.round(rect.width), h: Math.round(rect.height) }
                        });
                    }
                }
            });

            // 6. 搜索框区域
            info.searchArea = [];
            document.querySelectorAll('[class*="search"], [class*="filter"], [class*="query"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 0 && rect.width > 100) {
                    info.searchArea.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 100),
                        id: el.id,
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                        innerInputs: Array.from(el.querySelectorAll('input')).map(inp => ({
                            type: inp.type, placeholder: inp.placeholder, value: inp.value
                        }))
                    });
                }
            });

            return info;
        }
        """)

        print(json.dumps(result, ensure_ascii=False, indent=2))

asyncio.run(deep_inspect())
