import asyncio
import json
from patchright.async_api import async_playwright

async def extract_structures():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        result = await boss_page.evaluate("""
        () => {
            const info = {};

            // ============ 1. 简历浮层结构 ============
            const dialog = document.querySelector('.dialog-wrap.active');
            if (dialog) {
                const dialogContent = dialog.querySelector('.dialog-container, .dialog-content, [class*="dialog"]');

                // 浮层内所有有意义的区块
                info.dialogStructure = [];
                dialog.querySelectorAll('[class]').forEach(el => {
                    const cls = el.className.toString();
                    const rect = el.getBoundingClientRect();
                    if (rect.height > 30 && rect.width > 100) {
                        info.dialogStructure.push({
                            tag: el.tagName.toLowerCase(),
                            className: cls.substring(0, 100),
                            textPreview: (el.innerText || '').substring(0, 60).replace(/\\n/g, ' | '),
                            rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                            depth: (function(e) { let d=0; while(e.parentElement){d++;e=e.parentElement;} return d; })(el)
                        });
                    }
                });
                // 只保留前 40 个关键结构
                info.dialogStructure = info.dialogStructure.slice(0, 40);

                // 简历浮层内的关键数据
                info.resumeData = {};
                const resumeWrap = dialog.querySelector('.resume-detail-wrap');
                if (resumeWrap) {
                    info.resumeData.sections = [];
                    resumeWrap.querySelectorAll('[class]').forEach(el => {
                        const cls = el.className.toString();
                        if (cls.includes('title') || cls.includes('section') || cls.includes('info') || 
                            cls.includes('name') || cls.includes('education') || cls.includes('work') ||
                            cls.includes('skill') || cls.includes('expect') || cls.includes('advantage')) {
                            info.resumeData.sections.push({
                                className: cls.substring(0, 80),
                                text: (el.innerText || '').substring(0, 100).replace(/\\n/g, ' | ')
                            });
                        }
                    });
                    info.resumeData.sections = info.resumeData.sections.slice(0, 30);
                }
            }

            // ============ 2. 主容器 #wrap 内的结构 ============
            const wrap = document.getElementById('wrap');
            if (wrap) {
                info.wrapChildren = Array.from(wrap.children).map(el => ({
                    tag: el.tagName.toLowerCase(),
                    className: (el.className || '').toString().substring(0, 100),
                    id: el.id,
                    rect: {
                        w: Math.round(el.getBoundingClientRect().width),
                        h: Math.round(el.getBoundingClientRect().height)
                    },
                    childCount: el.children.length
                }));

                // 查找候选人列表 (在 wrap 内，dialog 外)
                info.candidateList = [];
                wrap.querySelectorAll('li, [class*="item"], [class*="card"]').forEach(el => {
                    // 排除 dialog 内的元素
                    if (dialog && dialog.contains(el)) return;
                    const rect = el.getBoundingClientRect();
                    if (rect.height > 40 && rect.width > 200) {
                        const links = el.querySelectorAll('a[href]');
                        const hasGeekLink = Array.from(links).some(a => a.href.includes('geek'));
                        info.candidateList.push({
                            tag: el.tagName.toLowerCase(),
                            className: (el.className || '').toString().substring(0, 100),
                            text: (el.innerText || '').substring(0, 80).replace(/\\n/g, ' | '),
                            rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                            hasGeekLink: hasGeekLink,
                            linkHref: hasGeekLink ? Array.from(links).find(a => a.href.includes('geek'))?.href : ''
                        });
                    }
                });
                info.candidateList = info.candidateList.slice(0, 20);
            }

            // ============ 3. 左侧菜单结构 ============
            info.menuItems = [];
            document.querySelectorAll('[class*="menu"] a, [class*="sidebar"] a, nav a').forEach(el => {
                const text = (el.innerText || '').trim();
                if (text && text.length < 30) {
                    info.menuItems.push({
                        text: text,
                        href: el.href,
                        className: (el.className || '').toString().substring(0, 60),
                        active: el.className.toString().includes('active') || el.className.toString().includes('current')
                    });
                }
            });

            return info;
        }
        """)

        print(json.dumps(result, ensure_ascii=False, indent=2))

asyncio.run(extract_structures())
