                break

        # 先提取浮层内简历的详细结构（wasm渲染的内容可能在 canvas/iframe 里）
        resume_info = await boss_page.evaluate("""
        () => {
            const dialog = document.querySelector('.dialog-wrap.active');
            if (!dialog) return { error: 'no dialog' };

            const info = {};

            // 检查是否有 canvas (wasm 渲染)
            info.hasCanvas = !!dialog.querySelector('canvas');
            info.hasIframe = !!dialog.querySelector('iframe');

            // 获取 resume-detail-wrap 的完整 innerHTML 结构
            const resumeWrap = dialog.querySelector('.resume-detail-wrap');
            if (resumeWrap) {
                // 获取所有直接子元素
                info.resumeChildren = Array.from(resumeWrap.querySelectorAll('*')).slice(0, 50).map(el => ({
                    tag: el.tagName.toLowerCase(),
                    className: (el.className || '').toString().substring(0, 80),
                    text: (el.innerText || '').substring(0, 60).replace(/\\n/g, ' | '),
                    childCount: el.children.length
                })).filter(x => x.text || x.childCount > 0);
            }

            // 关闭按钮
            info.closeButtons = [];
            dialog.querySelectorAll('[class*="close"], [class*="iboss-close"], .boss-popup__close').forEach(el => {
                info.closeButtons.push({
                    tag: el.tagName.toLowerCase(),
                    className: (el.className || '').toString().substring(0, 80),
                    text: (el.innerText || '').trim().substring(0, 30)
                });
            });

            // 浮层外层的关闭蒙层
            info.layerMask = [];
            dialog.querySelectorAll('.boss-layer__wrapper, .boss-popup__mask, [class*="mask"]').forEach(el => {
                info.layerMask.push({
                    tag: el.tagName.toLowerCase(),
                    className: (el.className || '').toString().substring(0, 80)
                });
            });

            return info;
        }
        """)

        print("=== 浮层简历结构 ===")
        print(json.dumps(resume_info, ensure_ascii=False, indent=2))

        # 关闭浮层
        closed = await boss_page.evaluate("""
        () => {
            // 方法1: 找关闭按钮
            const closeBtn = document.querySelector('.boss-popup__close, [class*="iboss-close"], .dialog-wrap.active [class*="close"]');
            if (closeBtn) {
                closeBtn.click();
                return 'clicked close button: ' + closeBtn.className;
            }
            // 方法2: 点击蒙层
            const mask = document.querySelector('.boss-layer__wrapper');
            if (mask) {
                mask.click();
                return 'clicked mask layer';
            }
            return 'no close method found';
        }
        """)
        print(f"\n关闭浮层: {closed}")

        # 等待浮层消失
        await asyncio.sleep(1)

        # 现在提取候选人列表
        list_info = await boss_page.evaluate("""
        () => {
            const info = {};

            // #container 的完整结构
            const container = document.getElementById('container');
            if (container) {
                info.containerHTML = container.innerHTML.substring(0, 500);
                info.containerChildren = Array.from(container.querySelectorAll('*')).slice(0, 60).map(el => {
                    const rect = el.getBoundingClientRect();
                    return {
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 100),
                        id: el.id,
                        text: (el.innerText || '').substring(0, 80).replace(/\\n/g, ' | '),
                        rect: rect.height > 0 ? { w: Math.round(rect.width), h: Math.round(rect.height) } : null,
                        childCount: el.children.length
                    };
                }).filter(x => x.rect && x.rect.h > 20);
            }

            // 全页面查找可能的候选人列表
            info.allLists = [];
            document.querySelectorAll('ul, ol, [class*="list"], [class*="card-wrap"]').forEach(el => {
                const dialog = document.querySelector('.dialog-wrap.active');
                if (dialog && dialog.contains(el)) return;
                const rect = el.getBoundingClientRect();
                if (rect.height > 100 && rect.width > 200 && el.children.length >= 2) {
                    info.allLists.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 100),
                        childCount: el.children.length,
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                        firstChildClass: (el.children[0]?.className || '').toString().substring(0, 80),
                        firstChildText: (el.children[0]?.innerText || '').substring(0, 100).replace(/\\n/g, ' | ')
                    });
                }
            });

            // 所有可见的大区域
            info.visibleAreas = [];
            document.querySelectorAll('#wrap > * > *, #wrap > *').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 50 && rect.width > 200) {
                    info.visibleAreas.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 100),
                        id: el.id,
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                        childCount: el.children.length
                    });
                }
            });

            return info;
        }
        """)

        print("\n=== 候选人列表结构 ===")
        print(json.dumps(list_info, ensure_ascii=False, indent=2))

asyncio.run(close_dialog_and_inspect())
