import asyncio
import json
from patchright.async_api import async_playwright

async def inspect_iframe():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        # 列出所有 frames
        print("=== 所有 Frames ===")
        for i, frame in enumerate(boss_page.frames):
            print(f"[{i}] name={frame.name!r}  url={frame.url}")
        print()

        # 找到搜索 iframe
        search_frame = None
        for frame in boss_page.frames:
            if 'searchFrame' in (frame.name or '') or 'frame/search' in (frame.url or ''):
                search_frame = frame
                break

        if not search_frame:
            print("❌ 没找到搜索 iframe")
            return

        print(f"✅ 找到搜索 iframe: {search_frame.url}\n")

        # 提取 iframe 内的完整结构
        result = await search_frame.evaluate("""
        () => {
            const info = {};

            // 1. 搜索输入区域
            info.searchInputs = [];
            document.querySelectorAll('input, textarea, [contenteditable]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 0) {
                    info.searchInputs.push({
                        tag: el.tagName.toLowerCase(),
                        type: el.type || '',
                        placeholder: el.placeholder || '',
                        name: el.name || '',
                        id: el.id || '',
                        className: (el.className || '').toString().substring(0, 80),
                        value: (el.value || '').substring(0, 50),
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });

            // 2. 筛选/过滤区域
            info.filters = [];
            document.querySelectorAll('[class*="filter"], [class*="condition"], [class*="option"], select').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 0 && rect.width > 50) {
                    info.filters.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 100),
                        text: (el.innerText || '').substring(0, 80).replace(/\\n/g, ' | '),
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });

            // 3. 候选人列表 — 找所有重复结构
            info.repeatedStructures = [];
            document.querySelectorAll('*').forEach(parent => {
                if (parent.children.length >= 3 && parent.children.length <= 200) {
                    const children = Array.from(parent.children);
                    const firstTag = children[0].tagName;
                    const firstClass = children[0].className?.toString() || '';
                    const sameCount = children.filter(c => 
                        c.tagName === firstTag && (c.className?.toString() || '') === firstClass
                    ).length;

                    if (sameCount >= 3 && firstClass) {
                        const rect = parent.getBoundingClientRect();
                        if (rect.height > 100) {
                            info.repeatedStructures.push({
                                parentTag: parent.tagName.toLowerCase(),
                                parentClass: (parent.className || '').toString().substring(0, 100),
                                parentId: parent.id,
                                childTag: firstTag.toLowerCase(),
                                childClass: firstClass.substring(0, 100),
                                totalChildren: parent.children.length,
                                sameClassChildren: sameCount,
                                parentRect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                                firstChildText: (children[0].innerText || '').substring(0, 120).replace(/\\n/g, ' | '),
                                firstChildHTML: children[0].innerHTML.substring(0, 300)
                            });
                        }
                    }
                }
            });

            // 4. 滚动容器
            info.scrollContainers = [];
            document.querySelectorAll('*').forEach(el => {
                const style = window.getComputedStyle(el);
                if ((style.overflowY === 'auto' || style.overflowY === 'scroll') && el.scrollHeight > el.clientHeight + 50) {
                    info.scrollContainers.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 100),
                        id: el.id,
                        scrollHeight: el.scrollHeight,
                        clientHeight: el.clientHeight,
                        childCount: el.children.length
                    });
                }
            });

            // 5. 所有按钮
            info.buttons = [];
            document.querySelectorAll('button, [role="button"], [class*="btn"]').forEach(el => {
                const text = (el.innerText || '').trim();
                const rect = el.getBoundingClientRect();
                if (text && rect.height > 0) {
                    info.buttons.push({
                        tag: el.tagName.toLowerCase(),
                        text: text.substring(0, 40),
                        className: (el.className || '').toString().substring(0, 80),
                        rect: { x: Math.round(rect.x), y: Math.round(rect.y) }
                    });
                }
            });

            // 6. 页面顶层结构
            info.topStructure = Array.from(document.body.children).map(el => {
                const rect = el.getBoundingClientRect();
                return {
                    tag: el.tagName.toLowerCase(),
                    className: (el.className || '').toString().substring(0, 100),
                    id: el.id,
                    rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                    childCount: el.children.length
                };
            }).filter(x => x.rect.h > 0);

            return info;
        }
        """)

        print(json.dumps(result, ensure_ascii=False, indent=2))

asyncio.run(inspect_iframe())
