import asyncio
import json
from patchright.async_api import async_playwright

async def extract_card_detail():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        search_frame = None
        for frame in boss_page.frames:
            if 'searchFrame' in (frame.name or ''):
                search_frame = frame
                break

        # 提取前 3 个候选人卡片的详细结构
        result = await search_frame.evaluate("""
        () => {
            const info = {};

            // 1. 卡片详细结构
            const cards = document.querySelectorAll('.card-list .geek-info-card');
            info.totalCards = cards.length;

            info.cardDetails = [];
            for (let i = 0; i < Math.min(3, cards.length); i++) {
                const card = cards[i];
                const a = card.querySelector('a');

                const detail = {
                    // a 标签属性
                    linkAttrs: {},
                    // 内部结构
                    structure: [],
                    // 完整文本
                    fullText: (card.innerText || '').replace(/\\n/g, ' | '),
                    // 完整 HTML (前2000字)
                    html: card.innerHTML.substring(0, 2000)
                };

                if (a) {
                    // 提取所有 data-* 属性
                    Array.from(a.attributes).forEach(attr => {
                        if (attr.name.startsWith('data-') || attr.name === 'href' || attr.name === 'ka') {
                            detail.linkAttrs[attr.name] = attr.value;
                        }
                    });
                }

                // 内部所有有 class 的元素
                card.querySelectorAll('[class]').forEach(el => {
                    const cls = el.className.toString();
                    detail.structure.push({
                        tag: el.tagName.toLowerCase(),
                        className: cls.substring(0, 80),
                        text: (el.innerText || '').substring(0, 60).replace(/\\n/g, ' | '),
                        directText: Array.from(el.childNodes).filter(n => n.nodeType === 3).map(n => n.textContent.trim()).filter(t => t).join(' ')
                    });
                });

                info.cardDetails.push(detail);
            }

            // 2. 搜索框和筛选器的精确选择器
            info.searchBox = {};
            const searchInput = document.querySelector('.search-input');
            if (searchInput) {
                const parent = searchInput.closest('[class]');
                info.searchBox = {
                    inputClass: searchInput.className,
                    inputValue: searchInput.value,
                    parentClass: (parent?.className || '').toString().substring(0, 80),
                    parentTag: parent?.tagName.toLowerCase()
                };
            }

            // 搜索按钮
            const searchBtn = document.querySelector('[class*="search"] button, button[class*="search"], [ka*="search"]');
            if (searchBtn) {
                info.searchButton = {
                    tag: searchBtn.tagName.toLowerCase(),
                    text: (searchBtn.innerText || '').trim(),
                    className: searchBtn.className.toString().substring(0, 80)
                };
            }

            // 3. 分页或加载更多
            info.pagination = [];
            document.querySelectorAll('[class*="page"], [class*="pager"], [class*="load-more"], [class*="换一换"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 0) {
                    info.pagination.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 80),
                        text: (el.innerText || '').trim().substring(0, 40)
                    });
                }
            });

            // 4. "换一换" 按钮
            const changeBtn = document.querySelector('.change-btn');
            if (changeBtn) {
                info.changeButton = {
                    className: changeBtn.className,
                    text: (changeBtn.innerText || '').trim(),
                    parentClass: (changeBtn.parentElement?.className || '').toString().substring(0, 80)
                };
            }

            return info;
        }
        """)

        # 打印卡片概览
        print(f"=== 候选人卡片结构 (共 {result['totalCards']} 张) ===\n")

        for i, card in enumerate(result['cardDetails']):
            print(f"--- 卡片 {i+1} ---")
            print(f"链接属性: {json.dumps(card['linkAttrs'], ensure_ascii=False)}")
            print(f"文本: {card['fullText'][:150]}")
            print(f"\n结构层级:")
            for s in card['structure']:
                text_preview = s['text'][:40] if s['text'] else ''
                direct = s['directText'][:30] if s['directText'] else ''
                print(f"  {s['tag']}.{s['className'][:50]}  text={text_preview!r}  direct={direct!r}")
            print()

        print("=== 搜索框 ===")
        print(json.dumps(result.get('searchBox', {}), ensure_ascii=False, indent=2))

        print("\n=== 搜索按钮 ===")
        print(json.dumps(result.get('searchButton', {}), ensure_ascii=False, indent=2))

        print("\n=== 换一换按钮 ===")
        print(json.dumps(result.get('changeButton', {}), ensure_ascii=False, indent=2))

        print("\n=== 分页 ===")
        print(json.dumps(result.get('pagination', []), ensure_ascii=False, indent=2))

asyncio.run(extract_card_detail())
PYEOF

