import asyncio
import json
from patchright.async_api import async_playwright

async def inspect_resume_and_contact():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        # 1. 检查简历 iframe
        print("=== Resume Iframe ===")
        resume_frame = None
        for frame in boss_page.frames:
            if 'c-resume' in (frame.url or ''):
                resume_frame = frame
                break

        if resume_frame:
            print(f"URL: {resume_frame.url}")
            resume_info = await resume_frame.evaluate("""
            () => {
                const info = {};
                info.bodyChildren = Array.from(document.body.children).map(el => ({
                    tag: el.tagName.toLowerCase(),
                    className: (el.className || '').toString().substring(0, 100),
                    id: el.id,
                    visible: el.offsetHeight > 0,
                    childCount: el.children.length,
                    textPreview: (el.innerText || '').substring(0, 100).replace(/\\n/g, ' | ')
                })).filter(x => x.visible || x.childCount > 0);
                return info;
            }
            """)
            print(json.dumps(resume_info, ensure_ascii=False, indent=2))
        else:
            print("No resume iframe found")

        # 2. 点击第一个候选人卡片来打开简历浮层
        search_frame = None
        for frame in boss_page.frames:
            if 'searchFrame' in (frame.name or ''):
                search_frame = frame
                break

        print("\n=== 点击候选人卡片 ===")
        click_result = await search_frame.evaluate("""
        () => {
            const card = document.querySelector('.card-list .geek-info-card a');
            if (card) {
                card.click();
                return {
                    clicked: true,
                    expect: card.dataset.expect,
                    jid: card.dataset.jid,
                    lid: card.dataset.lid
                };
            }
            return { clicked: false };
        }
        """)
        print(json.dumps(click_result, ensure_ascii=False, indent=2))

        # 等待浮层出现
        await asyncio.sleep(2)

        # 3. 检查浮层和简历 iframe 是否更新
        print("\n=== 浮层出现后 ===")

        # 重新检查 frames
        for frame in boss_page.frames:
            if 'c-resume' in (frame.url or '') or 'resume' in (frame.url or ''):
                print(f"Resume frame URL: {frame.url}")

                resume_content = await frame.evaluate("""
                () => {
                    const info = {};

                    // 简历内的所有区块
                    info.sections = [];
                    document.querySelectorAll('[class]').forEach(el => {
                        const cls = el.className.toString();
                        const rect = el.getBoundingClientRect();
                        if (rect.height > 20 && rect.width > 100 && (
                            cls.includes('name') || cls.includes('info') || cls.includes('section') ||
                            cls.includes('detail') || cls.includes('resume') || cls.includes('title') ||
                            cls.includes('education') || cls.includes('work') || cls.includes('skill') ||
                            cls.includes('expect') || cls.includes('basic') || cls.includes('advantage') ||
                            cls.includes('project') || cls.includes('desc')
                        )) {
                            info.sections.push({
                                tag: el.tagName.toLowerCase(),
                                className: cls.substring(0, 80),
                                text: (el.innerText || '').substring(0, 100).replace(/\\n/g, ' | ')
                            });
                        }
                    });
                    info.sections = info.sections.slice(0, 30);

                    // 完整文本前500字
                    info.fullText = (document.body.innerText || '').substring(0, 500).replace(/\\n/g, ' | ');

                    return info;
                }
                """)
                print(json.dumps(resume_content, ensure_ascii=False, indent=2))

        # 4. 检查浮层底部的操作按钮
        dialog_buttons = await boss_page.evaluate("""
        () => {
            const dialog = document.querySelector('.dialog-wrap.active');
            if (!dialog) return { error: 'no dialog' };

            const info = {};
            info.buttons = [];
            dialog.querySelectorAll('button, [role="button"], [class*="btn"]').forEach(el => {
                const text = (el.innerText || '').trim();
                const rect = el.getBoundingClientRect();
                if (text && rect.height > 0) {
                    info.buttons.push({
                        tag: el.tagName.toLowerCase(),
                        text: text.substring(0, 60),
                        className: (el.className || '').toString().substring(0, 80),
                        rect: { x: Math.round(rect.x), y: Math.round(rect.y), w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });

            // 沟通职位选择
            info.jobSelect = [];
            dialog.querySelectorAll('select, [class*="job"], [class*="position"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 0) {
                    info.jobSelect.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 80),
                        text: (el.innerText || '').substring(0, 60).replace(/\\n/g, ' | ')
                    });
                }
            });

            return info;
        }
        """)
        print("\n=== 浮层按钮 ===")
        print(json.dumps(dialog_buttons, ensure_ascii=False, indent=2))

asyncio.run(inspect_resume_and_contact())
