import asyncio
import json
from patchright.async_api import async_playwright

async def inspect_chat_flow():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        # 先看当前状态：浮层是否打开
        has_dialog = await boss_page.evaluate("""
        () => !!document.querySelector('.dialog-wrap.active')
        """)
        print(f"浮层状态: {'已打开' if has_dialog else '已关闭'}")

        if has_dialog:
            # 浮层已打开，点击浮层底部的联系按钮
            print("\n=== 点击浮层内的'联系Ta'按钮 ===")
            btn_info = await boss_page.evaluate("""
            () => {
                const btn = document.querySelector('.resume-footer button.btn-getcontact');
                if (!btn) return { found: false };
                return {
                    found: true,
                    text: btn.innerText.trim(),
                    className: btn.className,
                    disabled: btn.disabled
                };
            }
            """)
            print(json.dumps(btn_info, ensure_ascii=False, indent=2))

            if btn_info.get('found'):
                await boss_page.evaluate("""
                () => {
                    document.querySelector('.resume-footer button.btn-getcontact').click();
                }
                """)
                print("已点击联系按钮")
        else:
            # 没浮层，从列表上直接点联系按钮
            search_frame = None
            for frame in boss_page.frames:
                if 'searchFrame' in (frame.name or ''):
                    search_frame = frame
                    break

            print("\n=== 从卡片列表点击'联系Ta' ===")
            # 找一个非热搜（不需要3次配额）的候选人
            btn_info = await search_frame.evaluate("""
            () => {
                const cards = document.querySelectorAll('.card-list .geek-info-card');
                for (const card of cards) {
                    const btn = card.querySelector('button.btn-getcontact');
                    if (btn && !btn.closest('.num-not-enough')?.offsetHeight) {
                        return {
                            found: true,
                            text: btn.innerText.trim(),
                            className: btn.className,
                            cardName: card.querySelector('.name-label')?.innerText || ''
                        };
                    }
                }
                return { found: false };
            }
            """)
            print(json.dumps(btn_info, ensure_ascii=False, indent=2))

        # 等待聊天窗口出现
        await asyncio.sleep(3)

        # 检查页面变化
        print("\n=== 点击后页面状态 ===")
        print(f"当前 URL: {boss_page.url}")

        # 列出所有 frames
        print("\nFrames:")
        for i, frame in enumerate(boss_page.frames):
            print(f"  [{i}] name={frame.name!r}  url={frame.url[:80]}")

        # 检查是否出现了聊天窗口
        chat_info = await boss_page.evaluate("""
        () => {
            const info = {};

            // 检查全局聊天窗口
            const chatOuter = document.querySelector('.chat-global-outer-wrap');
            if (chatOuter) {
                const rect = chatOuter.getBoundingClientRect();
                info.chatOuter = {
                    className: chatOuter.className,
                    visible: rect.height > 0,
                    rect: { w: Math.round(rect.width), h: Math.round(rect.height) }
                };
            }

            // 检查是否有新的 dialog
            const dialogs = document.querySelectorAll('.dialog-wrap');
            info.dialogs = Array.from(dialogs).map(d => ({
                className: d.className.substring(0, 80),
                visible: d.classList.contains('active'),
                id: d.id
            }));

            // 检查所有可见的大元素
            info.visibleLarge = [];
            document.querySelectorAll('[class]').forEach(el => {
                const rect = el.getBoundingClientRect();
                const cls = el.className.toString();
                if (rect.height > 200 && rect.width > 200 && (
                    cls.includes('chat') || cls.includes('message') || cls.includes('im') ||
                    cls.includes('conversation') || cls.includes('dialog') || cls.includes('modal')
                )) {
                    info.visibleLarge.push({
                        tag: el.tagName.toLowerCase(),
                        className: cls.substring(0, 100),
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                        depth: (function(e) { let d=0; while(e.parentElement){d++;e=e.parentElement;} return d; })(el)
                    });
                }
            });

            // 检查聊天输入框
            info.chatInputs = [];
            document.querySelectorAll('#boss-chat-global-input, [contenteditable], textarea, [class*="chat-input"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 0) {
                    info.chatInputs.push({
                        tag: el.tagName.toLowerCase(),
                        id: el.id,
                        className: (el.className || '').toString().substring(0, 80),
                        contentEditable: el.contentEditable,
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });

            // 检查发送按钮
            info.sendButtons = [];
            document.querySelectorAll('button, [role="button"]').forEach(el => {
                const text = (el.innerText || '').trim();
                if (text.includes('发送') || text.includes('send')) {
                    const rect = el.getBoundingClientRect();
                    info.sendButtons.push({
                        tag: el.tagName.toLowerCase(),
                        text: text.substring(0, 30),
                        className: (el.className || '').toString().substring(0, 80),
                        visible: rect.height > 0,
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });

            return info;
        }
        """)

        print("\n=== 聊天窗口检查 ===")
        print(json.dumps(chat_info, ensure_ascii=False, indent=2))

asyncio.run(inspect_chat_flow())
