                    text: (d.innerText || '').substring(0, 200).replace(/\\n/g, ' | '),
                    closeBtn: !!d.querySelector('.boss-popup__close, .iboss-close'),
                    buttons: Array.from(d.querySelectorAll('button')).map(b => ({
                        text: (b.innerText || '').trim().substring(0, 40),
                        className: b.className.substring(0, 60)
                    }))
                };
            });
        }
        """)
        for d in dialogs_info:
            print(f"\n弹窗: {d['wrapperClass'][:60]}")
            print(f"  内容: {d['text'][:150]}")
