            const rect = chatWrap.getBoundingClientRect();
            const info = {
                found: true,
                visible: rect.height > 0,
                rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                className: chatWrap.className,
            };

            // 子结构
            info.children = [];
            chatWrap.querySelectorAll('[class]').forEach(el => {
                const r = el.getBoundingClientRect();
                const cls = el.className.toString();
                if (r.height > 10 && r.width > 10) {
                    info.children.push({
                        tag: el.tagName.toLowerCase(),
                        className: cls.substring(0, 80),
                        text: (el.innerText || '').substring(0, 60).replace(/\\n/g, ' | '),
                        rect: { w: Math.round(r.width), h: Math.round(r.height) }
                    });
                }
            });
            info.children = info.children.slice(0, 30);

            // 输入框
            info.inputs = [];
            chatWrap.querySelectorAll('input, textarea, [contenteditable]').forEach(el => {
                const r = el.getBoundingClientRect();
                info.inputs.push({
                    tag: el.tagName.toLowerCase(),
                    id: el.id,
                    className: (el.className || '').toString().substring(0, 80),
                    contentEditable: el.contentEditable,
                    visible: r.height > 0,
                    rect: { w: Math.round(r.width), h: Math.round(r.height) }
                });
            });

            // 按钮
            info.buttons = [];
            chatWrap.querySelectorAll('button, [class*="btn"]').forEach(el => {
                const text = (el.innerText || '').trim();
                const r = el.getBoundingClientRect();
