python3 << 'PYEOF'
import asyncio
import json
from patchright.async_api import async_playwright

async def inspect_chat_page():
    async with async_playwright() as p:
        browser = await p.chromium.connect_over_cdp('http://localhost:9222')
        context = browser.contexts[0]

        boss_page = None
        for page in context.pages:
            if 'zhipin.com' in page.url:
                boss_page = page
                break

        # 先关闭所有弹窗
        await boss_page.evaluate("""
        () => {
            document.querySelectorAll('.dialog-wrap.active').forEach(d => {
                const close = d.querySelector('.boss-popup__close, .iboss-close');
                if (close) close.click();
            });
        }
        """)
        await asyncio.sleep(1)

        # 导航到沟通页
        print("=== 导航到沟通页 ===")
        await boss_page.goto('https://www.zhipin.com/web/chat/index', wait_until='domcontentloaded', timeout=15000)
        await asyncio.sleep(3)

        print(f"URL: {boss_page.url}")
        print(f"Title: {await boss_page.title()}")

        # 列出 frames
        print("\nFrames:")
        for i, frame in enumerate(boss_page.frames):
            print(f"  [{i}] name={frame.name!r}  url={frame.url[:100]}")

        # 检查聊天页面结构
        chat_structure = await boss_page.evaluate("""
        () => {
            const info = {};

            // 1. 聊天列表（左侧会话列表）
            info.conversationList = [];
            document.querySelectorAll('[class*="chat-item"], [class*="conversation"], [class*="session"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 20) {
                    info.conversationList.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 80),
                        text: (el.innerText || '').substring(0, 80).replace(/\\n/g, ' | ')
                    });
                }
            });
            info.conversationList = info.conversationList.slice(0, 10);

            // 2. 聊天输入区域
            info.chatInputs = [];
            document.querySelectorAll('#boss-chat-global-input, [contenteditable="true"], textarea, [class*="chat-input"], [class*="editor"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                info.chatInputs.push({
                    tag: el.tagName.toLowerCase(),
                    id: el.id,
                    className: (el.className || '').toString().substring(0, 80),
                    contentEditable: el.contentEditable,
                    visible: rect.height > 0,
                    rect: { w: Math.round(rect.width), h: Math.round(rect.height) },
                    placeholder: el.getAttribute('placeholder') || el.dataset?.placeholder || ''
                });
            });

            // 3. 发送按钮
            info.sendButtons = [];
            document.querySelectorAll('button, [role="button"], [class*="btn"]').forEach(el => {
                const text = (el.innerText || '').trim();
                const rect = el.getBoundingClientRect();
                if (rect.height > 0 && (text.includes('发送') || text.includes('send') || 
                    el.className.toString().includes('send'))) {
                    info.sendButtons.push({
                        tag: el.tagName.toLowerCase(),
                        text: text.substring(0, 40),
                        className: (el.className || '').toString().substring(0, 80),
                        rect: { x: Math.round(rect.x), y: Math.round(rect.y), w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });

            // 4. 主要布局区域
            info.mainAreas = [];
            document.querySelectorAll('#wrap > *, #container > *, [class*="chat-wrap"], [class*="chat-box"], [class*="im-"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 100 && rect.width > 100) {
                    info.mainAreas.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 100),
                        id: el.id,
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });

            // 5. 消息列表区域
            info.messageArea = [];
            document.querySelectorAll('[class*="message"], [class*="msg-"], [class*="bubble"]').forEach(el => {
                const rect = el.getBoundingClientRect();
                if (rect.height > 30 && rect.width > 100) {
                    info.messageArea.push({
                        tag: el.tagName.toLowerCase(),
                        className: (el.className || '').toString().substring(0, 80),
                        text: (el.innerText || '').substring(0, 60).replace(/\\n/g, ' | '),
                        rect: { w: Math.round(rect.width), h: Math.round(rect.height) }
                    });
                }
            });
            info.messageArea = info.messageArea.slice(0, 15);

            return info;
        }
        """)

        print("\n=== 聊天页结构 ===")
        print(json.dumps(chat_structure, ensure_ascii=False, indent=2))

asyncio.run(inspect_chat_page())
PYEOF

