"""Candidate search module for Boss直聘.

Handles searching for candidates on Boss直聘's talent search pages.
Search page: /web/chat/search — candidates are inside iframe[name='searchFrame'].

CRITICAL ARCHITECTURE NOTE:
The search results live inside an iframe (searchFrame), NOT the main page DOM.
All evaluate() calls must target the iframe frame, not page directly.
Search uses "换一换" button to refresh results, not infinite scroll.
Candidate IDs come from data-expect attribute on card links.
"""

import hashlib
from dataclasses import dataclass, field
from typing import List, Optional, Set

from patchright.async_api import Page, Frame
from loguru import logger
from rich.console import Console
from rich.table import Table

from src.core.browser import BrowserManager, get_browser_manager
from src.utils.delays import async_random_delay
from src.utils.rate_limiter import get_rate_limiter, async_check_rate_limit
from src.utils.captcha import check_captcha
from src.utils.retry import retry_navigation
from src.models.database import Candidate, SearchHistory, get_db_manager
console = Console()


@dataclass
class CandidateBasic:
    """Basic candidate info extracted from search results."""
    boss_id: str
    name: str
    title: str
    company: str
    location: Optional[str] = None
    salary_expect: Optional[str] = None
    work_years: Optional[str] = None
    education_level: Optional[str] = None
    profile_url: Optional[str] = None
    active_status: Optional[str] = None
    school: Optional[str] = None
    major: Optional[str] = None
    job_status: Optional[str] = None
    self_desc: Optional[str] = None
    _score: int = field(default=0, init=False, repr=False)

    def __hash__(self):
        return hash(self.boss_id)

    def __eq__(self, other):
        if isinstance(other, CandidateBasic):
            return self.boss_id == other.boss_id
        return False


# Non-R&D roles to filter out
NON_RD_KEYWORDS = {
    "销售", "产品经理", "市场", "运营", "行政", "人事", "财务",
    "法务", "采购", "客服", "前台", "助理", "秘书",
}


def _is_non_rd_role(title: str) -> bool:
    """Check if title indicates a non-R&D role."""
    if not title:
        return False
    for keyword in NON_RD_KEYWORDS:
        if keyword in title:
            return True
    return False


def _generate_boss_id(name: str, company: str) -> str:
    """Generate a fallback Boss ID from name + company hash."""
    raw = f"{name}_{company}"
    h = hashlib.sha256(raw.encode()).hexdigest()[:20]
    return f"zp_{h}"


async def _get_search_frame(page: Page) -> Optional[Frame]:
    """Get the searchFrame iframe from the main page.

    Boss直聘 search page loads candidates inside iframe[name='searchFrame'].
    Returns the Frame object for executing JS inside the iframe.
    """
    frame = page.frame(name='searchFrame')
    if frame:
        return frame

    # Fallback: find by URL pattern
    for f in page.frames:
        if 'frame/search' in (f.url or ''):
            return f

    return None


# JavaScript extraction for candidates inside searchFrame iframe.
# Targets: div.card-list > li.geek-info-card > a[data-expect]
EXTRACT_CANDIDATES_JS = """
() => {
    const candidates = [];
    const cards = document.querySelectorAll('.card-list .geek-info-card');

    for (const card of cards) {
        try {
            const link = card.querySelector('a');
            if (!link) continue;

            // Candidate ID from data-expect attribute
            const expectId = link.dataset.expect || '';
            if (!expectId) continue;

            const bossId = 'zp_' + expectId;

            // Name (anonymized, e.g. "卿**")
            const nameEl = card.querySelector('.name-label');
            const name = nameEl ? nameEl.innerText.trim() : '';
            if (!name) continue;

            // Labels (e.g. "热搜")
            const labelEls = card.querySelectorAll('.card-label');
            const labels = Array.from(labelEls).map(el => el.innerText.trim()).filter(Boolean);

            // Active status (e.g. "3日内活跃")
            const activeEl = card.querySelector('.active-desc-text');
            const activeStatus = activeEl ? activeEl.innerText.trim() : '';

            // Info labels: age, work years, education, job status, salary
            const infoLabels = card.querySelectorAll('.info-labels > .label-text');
            const infoTexts = Array.from(infoLabels).map(el => el.innerText.trim());

            let age = '', workYears = '', education = '', jobStatus = '', salary = '';
            for (const text of infoTexts) {
                if (text.includes('岁')) age = text;
                else if (text.includes('年') && !text.includes('岁')) workYears = text;
                else if (['博士', '硕士', '本科', '大专', '中专', '高中'].some(d => text.includes(d))) education = text;
                else if (text.includes('在职') || text.includes('离职') || text.includes('求职')) jobStatus = text;
                else if (text.includes('K') || text.includes('k') || text.includes('薪')) salary = text;
            }

            // Self description / detail
            const detailEl = card.querySelector('.info-detail');
            const selfDesc = detailEl ? detailEl.innerText.trim() : '';

            // Expect city
            const expectCityEls = card.querySelectorAll('.expect-exp-box .t-tooltip-slot');
            const expectCity = Array.from(expectCityEls).map(el => el.innerText.trim()).filter(Boolean).join(' ');

            // Work experience (company + title)
            const workExpEls = card.querySelectorAll('.work-exp-box .t-tooltip-slot');
            const workExpTexts = Array.from(workExpEls).map(el => el.innerText.trim()).filter(Boolean);
            const company = workExpTexts[0] || '';
            const title = workExpTexts[1] || '';

            // Education (school + major)
            const eduExpEls = card.querySelectorAll('.edu-exp-box .t-tooltip-slot');
            const eduTexts = Array.from(eduExpEls).map(el => el.innerText.trim()).filter(Boolean);
            const school = eduTexts[0] || '';
            const major = eduTexts[1] || '';

            // Contact button status
            const contactBtn = card.querySelector('.btn-getcontact');
            const contactText = contactBtn ? contactBtn.innerText.trim() : '';

            // Elite/hot candidate flag
            const isElite = link.dataset.elitegeek === '1';

            candidates.push({
                boss_id: bossId,
                name: name,
                title: title,
                company: company,
                location: expectCity,
                salary_expect: salary,
                work_years: workYears,
                education_level: education,
                active_status: activeStatus,
                school: school,
                major: major,
                job_status: jobStatus,
                self_desc: selfDesc,
                age: age,
                labels: labels,
                is_elite: isElite,
                contact_text: contactText,
                profile_url: ''
            });
        } catch (e) {
            console.error('Error extracting candidate:', e);
        }
    }

    return candidates;
}
"""


